class Solution {
public:
    const int MOD = 1e9 + 7;
    int numberOfStableArrays(int zero, int one, int limit) {
        int n = zero + one;
        vector<vector<vector<int>>> dp(n + 1, vector<vector<int>>(2, vector<int>(limit + 1, 0)));
        dp[0][0][0] = 1;
        for (int i = 1; i <= n; i++) {
            for (int j = 0; j <= 1; j++) {
                for (int k = 0; k <= limit; k++) {
                    if (j == 0 && i - 1 <= zero) {
                        dp[i][j][k] = (dp[i][j][k] + dp[i - 1][j][min(limit, k + 1)]) % MOD;
                    }
                    if (j == 1 && i - 1 <= one) {
                        dp[i][j][k] = (dp[i][j][k] + dp[i - 1][0][1]) % MOD;
                        dp[i][j][k] = (dp[i][j][k] + dp[i - 1][1][1]) % MOD;
                    }
                }
            }
        }
        return dp[n][1][0];
    }
};
